openscad:
$fn = 60;
case_diameter = 40; // [30:1:60]
case_height = 8; // [5:1:15]
dial_diameter = 34; // [25:1:55]
dial_thickness = 1.5; // [0.5:0.5:3]
marker_length = 3; // [1:0.5:6]
marker_width = 1.2; // [0.5:0.2:2]
hand_length_h = 10; // [5:1:18]
hand_length_m = 14; // [6:1:20]
hand_width = 1.5; // [0.8:0.2:3]
crown_diameter = 5; // [3:0.5:8]

color("black")
union() {
    cylinder(d=case_diameter, h=case_height, center=true);
    translate([case_diameter/2-1,0,0])
        rotate([90,0,0])
        cylinder(d=crown_diameter, h=4, center=true);
}

color("white")
translate([0,0,case_height/2])
    cylinder(d=dial_diameter, h=dial_thickness, center=false);

color("black")
translate([0,0,case_height/2 + dial_thickness - 0.1])
for (i = [0:11]) {
    rotate([0,0,i*30])
        translate([dial_diameter/2 - marker_length - 1, -marker_width/2, 0])
            cube([marker_length, marker_width, 0.8]);
}

color("black")
translate([0,0,case_height/2 + dial_thickness])
union() {
    rotate([0,0,300])
        translate([-hand_width/2,0,0])
            cube([hand_width, hand_length_h, 1]);
    rotate([0,0,60])
        translate([-hand_width/2,0,0])
            cube([hand_width, hand_length_m, 1]);
    cylinder(d=3, h=1.2);
}
